import{_ as e,o as n,c as t,ag as s}from"./chunks/framework.DgcAjFZS.js";const u=JSON.parse('{"title":"为什么还需要推理优化工程师","description":"","frontmatter":{},"headers":[],"relativePath":"inference/why-optimize.md","filePath":"inference/why-optimize.md"}'),l={name:"inference/why-optimize.md"};function i(o,a,p,r,d,h){return n(),t("div",null,[...a[0]||(a[0]=[s(`<h1 id="为什么还需要推理优化工程师" tabindex="-1">为什么还需要推理优化工程师 <a class="header-anchor" href="#为什么还需要推理优化工程师" aria-label="Permalink to &quot;为什么还需要推理优化工程师&quot;">​</a></h1><blockquote><p>vLLM/SGLang 已经这么好了，还优化什么？ 2026-03-02</p></blockquote><hr><h2 id="核心观点" tabindex="-1">核心观点 <a class="header-anchor" href="#核心观点" aria-label="Permalink to &quot;核心观点&quot;">​</a></h2><p>vLLM/SGLang 是通用框架，但你的场景不是通用的。</p><p>打个比方：vLLM/SGLang 就像 MySQL — 开箱即用，大部分场景够了。但当你的业务到了一定规模和特殊性，你就需要 DBA 去调参数、改索引、甚至改存储引擎。推理优化工程师就是 LLM serving 的 &quot;DBA&quot;。</p><p>框架解决的是&quot;能跑起来&quot;，推理优化工程师解决的是&quot;跑得好、跑得快、跑得省&quot;。框架给你 80 分，剩下的 20 分需要根据你的模型、场景、硬件去定制，而这 20 分往往决定了成本是 100 万还是 50 万。</p><p>改造的动机来自三个层面：</p><hr><h2 id="_1-你的模型不是标准模型" tabindex="-1">1. 你的模型不是标准模型 <a class="header-anchor" href="#_1-你的模型不是标准模型" aria-label="Permalink to &quot;1. 你的模型不是标准模型&quot;">​</a></h2><p>vLLM/SGLang 对主流架构（Llama、Qwen）支持很好，但现实中：</p><ul><li>你的模型可能有自定义 attention（比如 DeepSeek 的 MLA，刚出来时没有框架支持）</li><li>你做了 SFT/DPO 后模型行为变了，decode 长度分布和通用模型不同，调度策略需要调整</li><li>你用 MoE 模型，expert 的激活模式和负载均衡需要针对你的数据分布优化</li><li>你加了 LoRA adapter，多 LoRA 并发时的调度和内存管理需要定制</li></ul><p><strong>真实案例：</strong> DeepSeek-V2 出来时用了 MLA（Multi-head Latent Attention），把 KV cache 压缩了 90%+。但当时 vLLM/SGLang 都不支持，SGLang 团队花了大量精力写专门的 MLA kernel 才跑起来，而且比 naive 实现快了 7 倍。</p><hr><h2 id="_2-你的场景有特殊约束" tabindex="-1">2. 你的场景有特殊约束 <a class="header-anchor" href="#_2-你的场景有特殊约束" aria-label="Permalink to &quot;2. 你的场景有特殊约束&quot;">​</a></h2><p>通用框架优化的是&quot;平均情况&quot;，但你的业务可能是：</p><h3 id="延迟敏感型-比如实时对话" tabindex="-1">延迟敏感型（比如实时对话） <a class="header-anchor" href="#延迟敏感型-比如实时对话" aria-label="Permalink to &quot;延迟敏感型（比如实时对话）&quot;">​</a></h3><ul><li>用户能忍受的 TTFT（首 token 时间）&lt; 200ms</li><li>通用调度器可能为了吞吐量牺牲延迟，你需要改调度优先级</li><li>可能需要定制 speculative decoding 的 draft model 选择策略</li></ul><h3 id="吞吐敏感型-比如批量处理、rl-rollout" tabindex="-1">吞吐敏感型（比如批量处理、RL rollout） <a class="header-anchor" href="#吞吐敏感型-比如批量处理、rl-rollout" aria-label="Permalink to &quot;吞吐敏感型（比如批量处理、RL rollout）&quot;">​</a></h3><ul><li>你不在乎单个请求的延迟，只要总吞吐量最大</li><li>可以用更激进的 batching 策略</li><li>RL 训练时 rollout 的推理有特殊模式 — 大量相似 prompt、需要多次采样</li></ul><h3 id="长上下文场景-比如文档分析" tabindex="-1">长上下文场景（比如文档分析） <a class="header-anchor" href="#长上下文场景-比如文档分析" aria-label="Permalink to &quot;长上下文场景（比如文档分析）&quot;">​</a></h3><ul><li>128K context 下 KV cache 占用巨大，标准 PagedAttention 可能不够</li><li>需要 KV cache 量化（FP8 KV）、分层缓存（GPU→CPU→SSD）</li><li>可能需要 sparse attention 或 sliding window 来降低计算量</li></ul><h3 id="多模态场景" tabindex="-1">多模态场景 <a class="header-anchor" href="#多模态场景" aria-label="Permalink to &quot;多模态场景&quot;">​</a></h3><ul><li>图片/视频的 prefill 计算量远大于文本</li><li>encoder 和 decoder 的调度需要分开优化</li></ul><hr><h2 id="_3-你的硬件不是标准配置" tabindex="-1">3. 你的硬件不是标准配置 <a class="header-anchor" href="#_3-你的硬件不是标准配置" aria-label="Permalink to &quot;3. 你的硬件不是标准配置&quot;">​</a></h2><p>框架默认优化的是 A100/H100，但你可能：</p><ul><li>用的是 A10、L40S 这种&quot;性价比卡&quot;，显存小、带宽低，需要更激进的量化和内存管理</li><li>多机多卡部署，跨节点通信成为瓶颈，需要优化 tensor parallel 的通信策略</li><li>用 AMD MI300X，kernel 需要适配 ROCm</li><li>混合部署：prefill 用大卡，decode 用小卡（PD 分离）</li></ul><hr><h2 id="真实工作场景" tabindex="-1">真实工作场景 <a class="header-anchor" href="#真实工作场景" aria-label="Permalink to &quot;真实工作场景&quot;">​</a></h2><p>用一个完整的案例串起来：</p><blockquote><p>老板说：我们要上线一个 AI 客服，用 Qwen2.5-72B，要求 TTFT &lt; 300ms，支持 1000 QPS，成本尽量低。</p></blockquote><h3 id="第一步-profiling-找瓶颈" tabindex="-1">第一步：Profiling（找瓶颈） <a class="header-anchor" href="#第一步-profiling-找瓶颈" aria-label="Permalink to &quot;第一步：Profiling（找瓶颈）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>先用 vLLM 跑 benchmark，发现：</span></span>
<span class="line"><span>- TTFT P99 = 800ms（超标）</span></span>
<span class="line"><span>- 吞吐量 = 400 QPS（不够）</span></span>
<span class="line"><span>- GPU 利用率只有 60%（有优化空间）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>用 nsight systems 看 kernel 执行时间线</span></span>
<span class="line"><span>发现瓶颈：prefill 阶段的 attention 计算太慢</span></span></code></pre></div><h3 id="第二步-系统级优化" tabindex="-1">第二步：系统级优化 <a class="header-anchor" href="#第二步-系统级优化" aria-label="Permalink to &quot;第二步：系统级优化&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>- 开启 chunked prefill，避免长 prompt 阻塞 decode</span></span>
<span class="line"><span>- 调整 max_num_seqs，找到 latency-throughput 的最优平衡点</span></span>
<span class="line"><span>- 开启 prefix caching（客服场景有大量相同的 system prompt）</span></span>
<span class="line"><span>- 尝试 PD 分离：prefill 和 decode 分到不同 GPU</span></span></code></pre></div><h3 id="第三步-模型级优化" tabindex="-1">第三步：模型级优化 <a class="header-anchor" href="#第三步-模型级优化" aria-label="Permalink to &quot;第三步：模型级优化&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>- 72B 模型太大，尝试 FP8 量化</span></span>
<span class="line"><span>- 跑精度评估，发现 FP8 在客服场景精度损失可接受</span></span>
<span class="line"><span>- 量化后显存减半，可以用更少的卡 → 成本降低</span></span>
<span class="line"><span>- KV cache 也做 FP8 量化，进一步省显存</span></span></code></pre></div><h3 id="第四步-kernel-级优化-如果前面还不够" tabindex="-1">第四步：Kernel 级优化（如果前面还不够） <a class="header-anchor" href="#第四步-kernel-级优化-如果前面还不够" aria-label="Permalink to &quot;第四步：Kernel 级优化（如果前面还不够）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>- 发现 attention kernel 在特定 seq_len 下性能不好</span></span>
<span class="line"><span>- 写一个针对这个 seq_len 分布优化的 Triton kernel</span></span>
<span class="line"><span>- 或者发现 RMSNorm + RoPE 可以 fuse 成一个 kernel，减少一次 HBM 读写</span></span>
<span class="line"><span>- 给 vLLM/SGLang 提 PR，或者维护内部 fork</span></span></code></pre></div><h3 id="第五步-持续监控和迭代" tabindex="-1">第五步：持续监控和迭代 <a class="header-anchor" href="#第五步-持续监控和迭代" aria-label="Permalink to &quot;第五步：持续监控和迭代&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>- 上线后监控 TTFT、TPS、GPU 利用率、错误率</span></span>
<span class="line"><span>- 流量模式变化时重新调优</span></span>
<span class="line"><span>- 新版本框架出来时评估是否升级</span></span></code></pre></div><hr><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>层次</th><th>框架已解决</th><th>你需要做的</th></tr></thead><tbody><tr><td>基础 serving</td><td>✅ continuous batching、PagedAttention</td><td>根据场景调参、选择框架</td></tr><tr><td>调度策略</td><td>✅ 通用调度器</td><td>针对你的流量模式定制优先级和抢占策略</td></tr><tr><td>内存管理</td><td>✅ 通用 KV cache 管理</td><td>KV cache 量化、分层缓存、prefix sharing 策略</td></tr><tr><td>模型适配</td><td>✅ 主流架构</td><td>自定义 attention、MoE 负载均衡、多 LoRA 调度</td></tr><tr><td>Kernel</td><td>✅ 通用 kernel</td><td>针对特定 shape/硬件写定制 kernel</td></tr><tr><td>量化</td><td>✅ 基础量化支持</td><td>选择方案、calibration、精度评估、mixed-precision 策略</td></tr><tr><td>系统架构</td><td>✅ 单机部署</td><td>PD 分离、多级缓存、跨节点通信优化</td></tr></tbody></table>`,45)])])}const b=e(l,[["render",i]]);export{u as __pageData,b as default};
